"""
v6.2 Mock Patterns - 외부 의존성을 제거하는 Mock 예제

테스트 시 실제 DB, API, SMTP를 사용하지 않고
Mock으로 대체하는 방법 교육
"""

from typing import List, Dict, Optional
from abc import ABC, abstractmethod
import time


class DatabaseService(ABC):
    """데이터베이스 서비스 인터페이스"""

    @abstractmethod
    def get_experiments(self) -> List[Dict]:
        """모든 실험 데이터 조회"""
        pass

    @abstractmethod
    def save_experiment(self, experiment: Dict) -> int:
        """실험 데이터 저장"""
        pass

    @abstractmethod
    def update_experiment(self, exp_id: int, data: Dict) -> bool:
        """실험 데이터 업데이트"""
        pass

    @abstractmethod
    def delete_experiment(self, exp_id: int) -> bool:
        """실험 데이터 삭제"""
        pass


class RealDatabaseService(DatabaseService):
    """실제 데이터베이스 서비스 (테스트에서는 Mock으로 교체)"""

    def __init__(self, connection_string: str):
        self.connection_string = connection_string
        self.experiments = []

    def get_experiments(self) -> List[Dict]:
        """실제 DB에서 데이터를 가져옴"""
        # 실제 환경에서는 DB 쿼리 실행
        # 테스트에서는 Mock으로 교체됨
        return self.experiments

    def save_experiment(self, experiment: Dict) -> int:
        """실제 DB에 저장"""
        exp_id = len(self.experiments) + 1
        experiment['id'] = exp_id
        self.experiments.append(experiment)
        return exp_id

    def update_experiment(self, exp_id: int, data: Dict) -> bool:
        """실제 DB에서 업데이트"""
        for exp in self.experiments:
            if exp.get('id') == exp_id:
                exp.update(data)
                return True
        return False

    def delete_experiment(self, exp_id: int) -> bool:
        """실제 DB에서 삭제"""
        self.experiments = [e for e in self.experiments if e.get('id') != exp_id]
        return True


class APIClient(ABC):
    """외부 API 클라이언트 인터페이스"""

    @abstractmethod
    def post_result(self, url: str, data: Dict) -> bool:
        """결과를 외부 API에 전송"""
        pass

    @abstractmethod
    def get_status(self, url: str) -> str:
        """상태 조회"""
        pass


