    def __init__(self, base_url: str, timeout: int = 5):
        self.base_url = base_url
        self.timeout = timeout

    def post_result(self, url: str, data: Dict) -> bool:
        """HTTP POST 요청 전송"""
        # 실제 환경에서는 requests.post() 사용
        # 테스트에서는 Mock으로 교체됨
        try:
