            return True
        except Exception:
            return False

    def get_status(self, url: str) -> str:
        """HTTP GET 요청"""
        # 실제 환경에서는 requests.get() 사용
        return "ok"


class EmailNotifier(ABC):
    """이메일 알림 서비스 인터페이스"""

    @abstractmethod
    def send_email(self, to: str, subject: str, body: str) -> bool:
