            return True
        except Exception:
            return False


class ExperimentService:
    """비즈니스 서비스 - DB + API + Email 조합

    테스트 시 모든 외부 의존성을 Mock으로 교체하여
    순수한 비즈니스 로직만 검증
    """

    def __init__(self, db: DatabaseService, api: APIClient, email: EmailNotifier):
        self.db = db
        self.api = api
        self.email = email

    def process_and_report(self, url: str, notify_email: str) -> str:
        """DB에서 데이터 가져와 API 전송 후 이메일 알림"""
        try:
            # 1. DB에서 데이터 조회
            experiments = self.db.get_experiments()

            # 2. 데이터 검증
            if not experiments:
                return "No experiments found"

            # 3. 외부 API에 전송
            success = self.api.post_result(url, {'count': len(experiments)})
            if not success:
                return "API transmission failed"

            # 4. 이메일 알림
            subject = f"실험 처리 완료: {len(experiments)}건"
            body = f"총 {len(experiments)}개의 실험을 처리했습니다."
            self.email.send_email(notify_email, subject, body)

            return f"Successfully processed {len(experiments)} experiments"
        except Exception as e:
            return f"Error: {str(e)}"

    def bulk_save_experiments(self, experiments: List[Dict]) -> int:
        """대량 실험 데이터 저장"""
        saved_count = 0
        for exp in experiments:
            try:
                self.db.save_experiment(exp)
                saved_count += 1
            except Exception:
                continue
        return saved_count

    def get_and_classify(self) -> Dict:
        """데이터 조회 및 분류"""
        experiments = self.db.get_experiments()
        return {
            'total': len(experiments),
            'data': experiments
        }


class CacheLayer:
    """캐시 계층 - Mock으로 테스트할 수 있는 예제"""

    def __init__(self, ttl: int = 300):
        self.cache = {}
        self.ttl = ttl
        self.timestamps = {}

    def get(self, key: str) -> Optional:
        """캐시에서 값 조회"""
        if key not in self.cache:
            return None

        # TTL 체크
        elapsed = time.time() - self.timestamps[key]
        if elapsed > self.ttl:
            del self.cache[key]
            del self.timestamps[key]
            return None

        return self.cache[key]

    def set(self, key: str, value) -> None:
        """캐시에 값 저장"""
        self.cache[key] = value
        self.timestamps[key] = time.time()

    def clear(self) -> None:
        """캐시 전체 삭제"""
        self.cache.clear()
        self.timestamps.clear()


class CircuitBreaker:
    """Circuit Breaker 패턴 - 실패 횟수 추적"""

    def __init__(self, failure_threshold: int = 3):
        self.failure_threshold = failure_threshold
        self.failure_count = 0
        self.is_open = False

    def call(self, func, *args, **kwargs):
        """Circuit Breaker를 통해 함수 호출"""
        if self.is_open:
            raise Exception("Circuit breaker is open")

        try:
            result = func(*args, **kwargs)
            self.failure_count = 0  # 성공 시 카운터 리셋
            return result
        except Exception as e:
            self.failure_count += 1
            if self.failure_count >= self.failure_threshold:
                self.is_open = True
            raise e

    def reset(self) -> None:
        """Circuit breaker 리셋"""
        self.failure_count = 0
        self.is_open = False

