"""
unittest 기초 - 다양한 assertion 메서드

사용자 제공 예제 (calculate_data_reliability) 포함
"""

import unittest
import sys
sys.path.insert(0, '/data/data/com.termux/files/home/kim/projects/gogs_python')

from src.v6_2_unit_testing.tdd_patterns import (
    calculate_data_reliability, DataValidator, ReportGenerator, ExperimentAnalyzer
)


class TestGogsReliability(unittest.TestCase):
    """사용자 제공 예제: calculate_data_reliability"""

    def test_calculate_data_reliability_normal(self):
        """정상 계산"""
        self.assertEqual(calculate_data_reliability(80, 100), 80.0)
        self.assertEqual(calculate_data_reliability(50, 100), 50.0)
        self.assertEqual(calculate_data_reliability(1, 2), 50.0)

    def test_calculate_data_reliability_zero_division(self):
        """분모가 0일 때"""
        self.assertEqual(calculate_data_reliability(10, 0), 0)
        self.assertEqual(calculate_data_reliability(0, 0), 0)

    def test_calculate_data_reliability_value_error(self):
        """success > total일 때 ValueError 발생"""
        with self.assertRaises(ValueError):
            calculate_data_reliability(150, 100)
        with self.assertRaises(ValueError):
            calculate_data_reliability(101, 100)

    def test_calculate_data_reliability_boundary(self):
        """경계값 테스트"""
        self.assertEqual(calculate_data_reliability(0, 100), 0.0)
        self.assertEqual(calculate_data_reliability(100, 100), 100.0)


class TestAssertEqual(unittest.TestCase):
    """assertEqual 메서드"""

    def test_equal_numbers(self):
        self.assertEqual(2 + 2, 4)

    def test_equal_strings(self):
        self.assertEqual("hello", "hello")

    def test_equal_lists(self):
        self.assertEqual([1, 2, 3], [1, 2, 3])

    def test_not_equal(self):
        self.assertNotEqual(2 + 2, 5)


class TestAssertAlmostEqual(unittest.TestCase):
    """부동소수점 비교 - assertAlmostEqual"""

    def test_almost_equal_floats(self):
        """부동소수점 오차 허용"""
        result = calculate_data_reliability(1, 3)  # 33.333...
        self.assertAlmostEqual(result, 33.33, places=2)

    def test_almost_equal_precision(self):
        """소수 자릿수 지정"""
        pi_approx = 3.141592653589793
        self.assertAlmostEqual(pi_approx, 3.14159, places=5)


class TestAssertTrue_False(unittest.TestCase):
    """assertTrue / assertFalse"""

    def test_true_assertion(self):
        validator = DataValidator()
        data = {'name': 'John', 'email': 'john@example.com'}
        self.assertTrue(validator.validate_researcher(data))

    def test_false_assertion(self):
        validator = DataValidator()
        data = {'name': '', 'email': 'john@example.com'}
        self.assertFalse(validator.validate_researcher(data))


class TestAssertIn_NotIn(unittest.TestCase):
    """assertIn / assertNotIn"""

    def test_assert_in(self):
        """항목이 컨테이너에 포함"""
        analyzer = ExperimentAnalyzer()
        grade = analyzer.classify_experiment(95)
        self.assertIn(grade, ['A', 'B', 'C', 'F'])

    def test_assert_not_in(self):
        """항목이 컨테이너에 미포함"""
        invalid_grade = 'Z'
        self.assertNotIn(invalid_grade, ['A', 'B', 'C', 'F'])


class TestAssertIsNone(unittest.TestCase):
    """assertIsNone / assertIsNotNone"""

    def test_is_none(self):
        result = None
        self.assertIsNone(result)

    def test_is_not_none(self):
        data = {'id': 1, 'name': 'Test'}
        self.assertIsNotNone(data)


class TestAssertRaises(unittest.TestCase):
    """assertRaises - 예외 발생 검증"""

    def test_raises_value_error(self):
        """ValueError 발생 확인"""
        with self.assertRaises(ValueError):
            calculate_data_reliability(150, 100)

    def test_raises_type_error(self):
        """TypeError 발생 확인"""
        with self.assertRaises(TypeError):
            # 문자열을 계산에 사용
            result = "invalid" / 100

    def test_no_exception(self):
        """예외가 발생하지 않아야 함"""
        try:
            result = calculate_data_reliability(80, 100)
            self.assertEqual(result, 80.0)
        except Exception as e:
            self.fail(f"예상치 않은 예외: {e}")


class TestDataValidator(unittest.TestCase):
    """DataValidator 종합 테스트"""

    def setUp(self):
        """각 테스트 전 validator 생성"""
        self.validator = DataValidator()

    def test_validate_researcher_valid(self):
        """유효한 연구자 데이터"""
        data = {'name': 'Alice', 'email': 'alice@example.com'}
        self.assertTrue(self.validator.validate_researcher(data))

    def test_validate_researcher_missing_name(self):
        """name 필드 누락"""
        data = {'email': 'alice@example.com'}
        self.assertFalse(self.validator.validate_researcher(data))

    def test_validate_researcher_empty_name(self):
        """name이 빈 문자열"""
        data = {'name': '', 'email': 'alice@example.com'}
        self.assertFalse(self.validator.validate_researcher(data))

    def test_validate_experiment_valid(self):
        """유효한 실험 데이터"""
        data = {'id': 1, 'name': 'Exp1', 'result': 95}
        self.assertTrue(self.validator.validate_experiment(data))

    def test_validate_experiment_invalid_result(self):
        """result가 0~100 범위 벗어남"""
        data = {'id': 1, 'name': 'Exp1', 'result': 150}
        self.assertFalse(self.validator.validate_experiment(data))

    def test_validate_email(self):
        """이메일 형식 검증"""
        self.assertTrue(self.validator.validate_email('test@example.com'))
        self.assertFalse(self.validator.validate_email('invalid-email'))

    def test_validate_score_range(self):
        """점수 범위 검증"""
