"""
환경 검증자 - 다양한 배포 환경 검증

핵심: 개발, 스테이징, 프로덕션 환경의 일관성 보장
"""

import os
import sys
import platform
from typing import Dict, List, Tuple
from dataclasses import dataclass


@dataclass
class EnvironmentSpec:
    """환경 사양"""
    name: str
    python_version: str
    os_type: str
    is_venv: bool
    installed_packages: int
    variables: Dict[str, str]


class EnvironmentValidator:
    """환경 검증자"""

    @staticmethod
    def get_environment_spec() -> EnvironmentSpec:
        """현재 환경 사양 추출

        Returns:
            EnvironmentSpec: 환경 정보
        """
        python_version = f"{sys.version_info.major}.{sys.version_info.minor}.{sys.version_info.micro}"
        os_type = platform.system()
        is_venv = "VIRTUAL_ENV" in os.environ

        # 설치된 패키지 개수
        import subprocess
        try:
            result = subprocess.run(
                ["pip", "list", "--format=json"],
                capture_output=True,
                text=True,
                check=True
            )
            import json
            packages = json.loads(result.stdout)
            package_count = len(packages)
        except:
            package_count = 0

        # 환경 변수
        critical_vars = {
            "PATH": os.environ.get("PATH", "")[:50] + "...",
            "HOME": os.environ.get("HOME", "N/A"),
            "VIRTUAL_ENV": os.environ.get("VIRTUAL_ENV", "N/A"),
        }

        return EnvironmentSpec(
            name="current_environment",
            python_version=python_version,
            os_type=os_type,
            is_venv=is_venv,
            installed_packages=package_count,
            variables=critical_vars
        )

    @staticmethod
    def validate_python_version(required_version: str = "3.8") -> Tuple[bool, str]:
        """Python 버전 검증

        Args:
            required_version: 필요한 최소 버전

        Returns:
            Tuple: (성공 여부, 메시지)
        """
        current = f"{sys.version_info.major}.{sys.version_info.minor}"
        required = tuple(map(int, required_version.split(".")))
        current_tuple = (sys.version_info.major, sys.version_info.minor)

        if current_tuple >= required:
            return True, f"✅ Python {current} (필요: {required_version}+)"
        else:
            return False, f"❌ Python {current} (필요: {required_version}+)"

    @staticmethod
    def validate_os_compatibility(supported_os: List[str] = None) -> Tuple[bool, str]:
        """OS 호환성 검증

        Args:
            supported_os: 지원 OS 목록 (Linux, Windows, Darwin)

        Returns:
            Tuple: (성공 여부, 메시지)
        """
        if supported_os is None:
            supported_os = ["Linux", "Windows", "Darwin"]

        current_os = platform.system()

        if current_os in supported_os:
            return True, f"✅ {current_os} (지원함)"
        else:
            return False, f"❌ {current_os} (미지원, 지원: {','.join(supported_os)})"

    @staticmethod
    def validate_dependencies(required_packages: Dict[str, str]) -> Tuple[bool, List[str]]:
        """필수 패키지 검증

        Args:
            required_packages: 필수 패키지 딕셔너리 {이름: 최소버전}

        Returns:
            Tuple: (성공 여부, 누락된 패키지)
        """
        import subprocess
        import json

        try:
            result = subprocess.run(
                ["pip", "list", "--format=json"],
                capture_output=True,
                text=True,
                check=True
            )
            installed = json.loads(result.stdout)
            installed_dict = {pkg["name"].lower(): pkg["version"] for pkg in installed}

        except:
            return False, list(required_packages.keys())

        missing = []
        for package, min_version in required_packages.items():
            if package.lower() not in installed_dict:
                missing.append(f"{package} (필수)")

        return len(missing) == 0, missing

    @staticmethod
    def validate_writable_directories(dirs: List[str] = None) -> Tuple[bool, List[str]]:
        """쓰기 가능 디렉토리 검증

        Args:
            dirs: 검증할 디렉토리 목록

        Returns:
            Tuple: (성공 여부, 쓰기 불가 디렉토리)
        """
        if dirs is None:
            dirs = [".", "./logs", "./data"]

        not_writable = []

        for dir_path in dirs:
            if not os.path.exists(dir_path):
                os.makedirs(dir_path, exist_ok=True)

            if not os.access(dir_path, os.W_OK):
                not_writable.append(dir_path)

        return len(not_writable) == 0, not_writable

    @staticmethod
    def validate_network_connectivity(test_url: str = "https://www.google.com") -> Tuple[bool, str]:
        """네트워크 연결성 검증

        Args:
            test_url: 테스트할 URL

        Returns:
            Tuple: (성공 여부, 메시지)
        """
        try:
            import urllib.request
            urllib.request.urlopen(test_url, timeout=3)
            return True, f"✅ 네트워크 연결됨"
        except:
            return False, f"❌ 네트워크 연결 불가"


class EnvironmentComparator:
    """환경 비교자 - 개발/스테이징/프로덕션 환경 비교"""

    @staticmethod
    def compare_environments(env1: EnvironmentSpec, env2: EnvironmentSpec) -> Dict:
        """두 환경 비교

        Args:
            env1: 첫 번째 환경
            env2: 두 번째 환경

        Returns:
            Dict: 비교 결과
        """
        comparison = {
            "python_compatible": env1.python_version == env2.python_version,
            "os_compatible": env1.os_type == env2.os_type,
            "venv_consistent": env1.is_venv == env2.is_venv,
            "package_count_diff": env2.installed_packages - env1.installed_packages,
            "differences": []
        }

        if env1.python_version != env2.python_version:
            comparison["differences"].append(
                f"Python: {env1.python_version} vs {env2.python_version}"
            )

        if env1.os_type != env2.os_type:
            comparison["differences"].append(
                f"OS: {env1.os_type} vs {env2.os_type}"
            )

        if env1.is_venv != env2.is_venv:
            comparison["differences"].append(
                f"VEnv: {env1.is_venv} vs {env2.is_venv}"
            )

        return comparison

    @staticmethod
    def generate_compatibility_report(environments: Dict[str, EnvironmentSpec]) -> Dict:
        """호환성 보고서 생성

        Args:
            environments: 환경 이름 -> 환경 사양 매핑

        Returns:
            Dict: 호환성 보고서
        """
        report = {
            "total_environments": len(environments),
            "compatible": True,
            "details": {}
        }

        env_list = list(environments.values())

        if len(env_list) >= 2:
            base_env = env_list[0]
            for i, env in enumerate(env_list[1:], 1):
                comparison = EnvironmentComparator.compare_environments(base_env, env)
                report["details"][f"env0_vs_env{i}"] = comparison

                if comparison["differences"]:
                    report["compatible"] = False

        return report


class DeploymentEnvironment:
    """배포 환경 설정"""

    ENVIRONMENTS = {
        "development": {
            "python_min": "3.8",
            "allow_venv": True,
            "required_packages": {},
            "debug": True
        },
        "staging": {
            "python_min": "3.9",
            "allow_venv": True,
            "required_packages": {
                "pytest": "7.0",
                "pytest-cov": "3.0"
            },
            "debug": False
        },
        "production": {
            "python_min": "3.9",
            "allow_venv": False,
            "required_packages": {},
            "debug": False
        }
    }

    @staticmethod
    def get_environment_config(env_name: str) -> Dict:
        """환경 설정 조회

        Args:
            env_name: 환경 이름

        Returns:
            Dict: 환경 설정
        """
        return DeploymentEnvironment.ENVIRONMENTS.get(env_name, {})

    @staticmethod
    def validate_for_environment(env_name: str) -> Tuple[bool, List[str]]:
        """특정 환경에 대한 검증

        Args:
            env_name: 환경 이름

        Returns:
            Tuple: (성공 여부, 오류 메시지 목록)
        """
        config = DeploymentEnvironment.get_environment_config(env_name)
        if not config:
            return False, [f"알 수 없는 환경: {env_name}"]

        errors = []

        # Python 버전 검증
        is_valid, msg = EnvironmentValidator.validate_python_version(config["python_min"])
        if not is_valid:
            errors.append(msg)

        # VEnv 검증
        is_venv = "VIRTUAL_ENV" in os.environ
        if env_name == "production" and is_venv:
            errors.append("⚠️  프로덕션 환경에서는 시스템 Python 사용 권장")

        # 필수 패키지 검증
        if config["required_packages"]:
            is_valid, missing = EnvironmentValidator.validate_dependencies(
                config["required_packages"]
            )
            if not is_valid:
                errors.extend(missing)

        return len(errors) == 0, errors

