  rpc CreateOrder(OrderRequest) returns (OrderResponse);
  rpc TrackOrder(TrackRequest) returns (stream StatusUpdate);
  rpc BatchOrder(stream OrderRequest) returns (OrderSummary);
  rpc ProcessOrders(stream OrderRequest) returns (stream StatusUpdate);
}

message OrderRequest {
