```python
# client/ecommerce_client.py

"""전자상거래 통합 클라이언트
grpc 미설치 시 mock 모드로 동작
"""

try:
    import grpc
    from ..generated import (
        order_pb2, order_pb2_grpc,
        payment_pb2, payment_pb2_grpc,
        delivery_pb2, delivery_pb2_grpc,
    )
    GRPC_AVAILABLE = True
except ImportError:
    GRPC_AVAILABLE = False

from ..discovery.service_registry import GogsServiceRegistry, ServiceInstance, ServiceStatus
from ..load_balancer.load_balancer import GogsLoadBalancer, BalancingStrategy
from ..services.order_service import OrderBusinessLogic
from ..services.payment_service import PaymentBusinessLogic
from ..services.delivery_service import DeliveryBusinessLogic
from ..interceptors.grpc_interceptors import (
    LoggingInterceptor, AuthInterceptor, PerformanceInterceptor
)


class EcommerceClient:
    """전자상거래 MSA 통합 클라이언트

    두 가지 동작 모드:
    1. GRPC 모드: 실제 gRPC 채널 사용
    2. LOCAL 모드: 비즈니스 로직 직접 호출 (테스트용)
    """

    def __init__(self, mode: str = "local"):
        self.mode = mode
        self.registry = GogsServiceRegistry()
        self.load_balancer = GogsLoadBalancer(
            self.registry, BalancingStrategy.ROUND_ROBIN
        )
        self.logging_interceptor = LoggingInterceptor()
        self.auth_interceptor = AuthInterceptor()
        self.perf_interceptor = PerformanceInterceptor()

        # Local mode: 비즈니스 로직 직접 참조
        self._order_logic = OrderBusinessLogic()
        self._payment_logic = PaymentBusinessLogic()
        self._delivery_logic = DeliveryBusinessLogic()

        self._setup_registry()

    def _setup_registry(self):
        """서비스 인스턴스 등록"""
        for port in [50051, 50052]:
            self.registry.register(ServiceInstance(
                service_name="order-service",
                host="localhost", port=port
            ))
        self.registry.register(ServiceInstance(
            service_name="payment-service",
            host="localhost", port=50053
        ))
        self.registry.register(ServiceInstance(
            service_name="delivery-service",
            host="localhost", port=50054
        ))

    def create_order(self, order_id: int, product: str,
                     quantity: int, price: float) -> dict:
        call_id = self.logging_interceptor.log_call(
            "CreateOrder", {"order_id": order_id, "product": product}
        )

        if self.mode == "grpc" and GRPC_AVAILABLE:
            instance = self.load_balancer.get_instance("order-service")
            channel = grpc.insecure_channel(instance.address)
            stub = order_pb2_grpc.OrderServiceStub(channel)
            request = order_pb2.OrderRequest(
                order_id=order_id, product=product,
                quantity=quantity, price=price
            )
            response = stub.CreateOrder(request)
            return {"success": response.success, "message": response.message,
                    "order_status": response.order_status}
        else:
            return self._order_logic.create_order(
                order_id, product, quantity, price
            )

    def track_order_stream(self, order_id: int):
        """Server Streaming: 주문 추적 스트림"""
        self.logging_interceptor.log_call("TrackOrder", {"order_id": order_id})

        if self.mode == "grpc" and GRPC_AVAILABLE:
            instance = self.load_balancer.get_instance("order-service")
            channel = grpc.insecure_channel(instance.address)
            stub = order_pb2_grpc.OrderServiceStub(channel)
            for update in stub.TrackOrder(order_pb2.TrackRequest(order_id=order_id)):
                yield {"status": update.status, "timestamp": update.timestamp}
        else:
            yield from self._order_logic.track_order_stream(order_id)

    # payment, delivery 메서드들도 동일 패턴...

    def get_stats(self) -> dict:
        return {
            "logging": self.logging_interceptor.get_stats(),
            "load_balancer": self.load_balancer.get_stats(),
            "performance": {
                method: self.perf_interceptor.get_stats(method)
                for method in ["CreateOrder", "ProcessPayment", "CreateDelivery"]
            }
        }
```

