class TestEcommerceClientLocalMode(unittest.TestCase):
    """서버 없이 local 모드로 전체 워크플로우 테스트"""

    def setUp(self):
        self.client = EcommerceClient(mode="local")

    def test_full_order_flow(self):
        # 주문 생성
        order_result = self.client.create_order(1001, "Python Book", 2, 29.99)
        self.assertTrue(order_result["success"])

        # 주문 추적 스트리밍
        updates = list(self.client.track_order_stream(1001))
        self.assertGreater(len(updates), 0)

        # 결제 처리
        payment_result = self.client.process_payment(
            order_id=1001, amount=59.98, method="card"
        )
        self.assertTrue(payment_result["success"])

        # 배송 생성
        delivery_result = self.client.create_delivery(
            order_id=1001, address="Seoul, Korea"
        )
        self.assertTrue(delivery_result["success"])

    def test_load_balancer_round_robin(self):
        # order-service 인스턴스 2개 등록됨
        instances_used = set()
        for i in range(4):
            instance = self.client.load_balancer.get_instance("order-service")
            instances_used.add(instance.port)

        # 두 포트가 번갈아 사용됨
        self.assertEqual(len(instances_used), 2)

    def test_service_registry_discover(self):
        instances = self.client.registry.discover("order-service")
        self.assertGreater(len(instances), 0)
        self.assertEqual(instances[0].service_name, "order-service")

    def test_interceptor_stats_accumulated(self):
        for i in range(3):
            self.client.create_order(i, f"item-{i}", 1, 10.0)

        stats = self.client.get_stats()
        self.assertEqual(stats["logging"]["total_calls"], 3)
