## 4. 각 .proto 파일 상세 설계

### order.proto
```protobuf
syntax = "proto3";
package ecommerce;
option python_package = "src.v7_2_grpc.generated";

service OrderService {
  rpc CreateOrder(OrderRequest) returns (OrderResponse);
  rpc TrackOrder(TrackRequest) returns (stream StatusUpdate);
  rpc BatchOrder(stream OrderRequest) returns (OrderSummary);
  rpc ProcessOrders(stream OrderRequest) returns (stream StatusUpdate);
}

message OrderRequest {
  int32 order_id = 1;
  string product = 2;
  int32 quantity = 3;
  float price = 4;
}
message OrderResponse {
  bool success = 1;
  string message = 2;
  string order_status = 3;
}
message TrackRequest { int32 order_id = 1; }
message StatusUpdate {
  string status = 1;
  string timestamp = 2;
}
message OrderSummary {
  int32 total_orders = 1;
  float total_price = 2;
}
```

### payment.proto
```protobuf
syntax = "proto3";
package ecommerce;

service PaymentService {
  rpc ProcessPayment(PaymentRequest) returns (PaymentResponse);
  rpc StreamTransactions(PaymentFilter) returns (stream Transaction);
  rpc BatchPayments(stream PaymentRequest) returns (PaymentSummary);
  rpc PaymentStream(stream PaymentRequest) returns (stream PaymentResponse);
}

message PaymentRequest {
  int32 order_id = 1;
  float amount = 2;
  string method = 3;  // "card", "bank", "crypto"
}
message PaymentResponse {
  bool success = 1;
  string transaction_id = 2;
  string status = 3;
}
message PaymentFilter { string method = 1; }
message Transaction {
  string transaction_id = 1;
  float amount = 2;
  string timestamp = 3;
}
message PaymentSummary {
  int32 total_count = 1;
  float total_amount = 2;
  int32 success_count = 3;
}
```

### delivery.proto
```protobuf
syntax = "proto3";
package ecommerce;

service DeliveryService {
  rpc CreateDelivery(DeliveryRequest) returns (DeliveryResponse);
  rpc TrackShipment(TrackShipmentRequest) returns (stream ShipmentUpdate);
  rpc BatchDeliveries(stream DeliveryRequest) returns (DeliverySummary);
  rpc ManageDeliveries(stream DeliveryRequest) returns (stream DeliveryResponse);
}

message DeliveryRequest {
  int32 order_id = 1;
  string address = 2;
  string courier = 3;  // "express", "standard", "economy"
}
message DeliveryResponse {
  bool success = 1;
  string tracking_number = 2;
  string estimated_delivery = 3;
}
message TrackShipmentRequest { string tracking_number = 1; }
message ShipmentUpdate {
  string location = 1;
  string status = 2;
  string timestamp = 3;
}
message DeliverySummary {
  int32 total_deliveries = 1;
  int32 express_count = 2;
  float avg_delivery_days = 3;
}
